const slackData = $('Extract Keywords & Detect Intent').first().json;
const searchResultNode = $('Has Results?').first().json;
const workflows = searchResultNode.workflows || [];
const searchQuery = slackData.searchQuery || '';

const results = workflows.slice(0, 5).map((w, i) =>
  `${i + 1}. <https://n8n.io/workflows/${w.id}|${w.name}>`
).join('\n');

let tips = '';
try {
  const aiResponse = $input.first().json;
  if (aiResponse.choices && aiResponse.choices[0]) {
    tips = aiResponse.choices[0].message.content;
  }
} catch (e) {
  tips = '';
}

let text = `*Search:* \`${searchQuery}\`\n\n`;
text += `*Templates found:*\n${results}\n\n`;

if (tips) {
  text += `---\n`;
  text += `*Tips & ideas para tu workflow:*\n${tips}\n`;
}

text += `\n_Powered by n8n Template Bot_`;

return [{
  json: {
    ...slackData,
    text,
    resultCount: workflows.length,
    fromCache: false
  }
}];

const slackData = $('Extract Keywords & Detect Intent').first().json;
const searchQuery = slackData.searchQuery || '';

let suggestions = '';
try {
  const aiResponse = $input.first().json;
  if (aiResponse.choices && aiResponse.choices[0]) {
    suggestions = aiResponse.choices[0].message.content;
  }
} catch (e) {
  suggestions = '';
}

let text = `*Search:* \`${searchQuery}\`\n\n`;
text += `No encontre templates exactos para tu busqueda.\n\n`;

if (suggestions) {
  text += `*Pero aqui van algunas sugerencias:*\n${suggestions}\n\n`;
}

text += `_Intenta con otros keywords o escribe \`@bot categories\` para ver categorias._\n`;
text += `_Powered by n8n Template Bot_`;

return [{
  json: {
    ...slackData,
    text,
    resultCount: 0,
    fromCache: false
  }
}];

const rows = $input.all().map(i => i.json);
const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);

const recent = rows.filter(r => new Date(r.Timestamp) >= oneWeekAgo);

if (recent.length === 0) {
  return [{ json: { text: '*Weekly Bot Report:* No searches this week.' } }];
}

const queryCounts = {};
const intentCounts = { search: 0, help: 0, categories: 0 };
let totalResults = 0;
let cacheHits = 0;

for (const row of recent) {
  const q = (row.Keywords || row.Query || '').toLowerCase();
  queryCounts[q] = (queryCounts[q] || 0) + 1;
  intentCounts[row.Intent || 'search']++;
  totalResults += parseInt(row.ResultCount || '0');
  if (row.FromCache === 'true' || row.FromCache === true) cacheHits++;
}

const topSearches = Object.entries(queryCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([q, count], i) => `${i + 1}. \`${q}\` (${count}x)`)
  .join('\n');

const avgResults = recent.length > 0 ? (totalResults / recent.length).toFixed(1) : 0;

const text = '*Weekly n8n Template Bot Report*\n' +
  '---\n\n' +
  `*Total searches:* ${recent.length}\n` +
  `*Search:* ${intentCounts.search} | *Help:* ${intentCounts.help} | *Categories:* ${intentCounts.categories}\n` +
  `*Avg results per search:* ${avgResults}\n` +
  `*Cache hits:* ${cacheHits} (${((cacheHits/recent.length)*100).toFixed(0)}%)\n\n` +
  `*Top searches this week:*\n${topSearches}\n\n` +
  '_Auto-generated weekly report_';

return [{ json: { text } }];
